WebLink.url:
//Obtenemos el id de la organizacion
var idOrganizacion = '{!$Organization.Id}';

//Objeto url
var parametros = {};

var url = '';

if(idOrganizacion == '00DZ000000MiG3Y'){

	//Cargamos parámetro y valor [ TEST ]

	parametros['CF00NZ0000001PAKy'] = '{!JSENCODE(Comprobante_de_Pago__c.Cliente__c)}';
	//parametros['CF00NZ0000001PAKy_lkid'] = '{!Aplicacion__c.Cuenta_OriginanteId__c}';
	parametros['CF00NG000000Dy8rW'] = '{!Comprobante_de_Pago__c.Name}';
	//parametros['CF00NG000000Dy8rW_lkid'] = '{!Aplicacion__c.Comprobante_de_PagoId__c}';

	url = '/a0C/e?';

}else if(idOrganizacion == '00DG0000000ii42'){

	//Cargamos parámetro y valor [ PROD ]

	parametros['CF00NG000000ERvfp'] = '{!JSENCODE(Comprobante_de_Pago__c.Cliente__c)}';
	//parametros['CF00NG000000ERvfp_lkid'] = '{!Aplicacion__c.Cuenta_OriginanteId__c}';
	parametros['CF00NG000000Dy8rW'] = '{!Comprobante_de_Pago__c.Name}';
	//parametros['CF00NG000000Dy8rW_lkid'] = '{!Aplicacion__c.Comprobante_de_PagoId__c}';

	url = '/a0C/e?';
}



//Si se introdujeron parametros
if(!isEmpty(parametros)){

	var p = ''; 

	//Obtenemos la parametros
	for(var prop in parametros) {
		if(parametros.hasOwnProperty(prop)){
			p += (p.length == 0)?prop+'='+parametros[prop]:'&'+prop+'='+parametros[prop]; 
		}
	}

	//Completamos la URL
	url += p+'&retURL='+'{!Comprobante_de_Pago__c.Id}';

	//Redirigimos
	window.location.href = url;

}

function isEmpty(obj) {
	for(var prop in obj) {
		if(obj.hasOwnProperty(prop))
			return false;
		}

	return true;
}
